function openManualSeeding(t){
  var participants=[].concat(t.participants||[]);
  var size=1; while(size<participants.length) size*=2;
  var slots=[];
  for(var i=0;i<size;i++) slots.push(participants[i]||null);
  window._seedingSlots=slots;
  window._seedingTournament=t;
  showManualSeedingModal();
}

function showManualSeedingModal(){
  var t=window._seedingTournament;
  var slots=window._seedingSlots;
  var html='<div style="font-size:11px;color:var(--tx3);margin-bottom:12px">Assignez les équipes dans l\'ordre souhaité du bracket.</div>';
  html+='<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:12px">';
  slots.forEach(function(slot,i){
    html+='<div style="background:var(--bg3);border:1px solid '+(slot?'var(--golddim)':'var(--b1)')+';border-radius:3px;padding:8px 10px">';
    html+='<div style="font-size:10px;color:var(--tx3);margin-bottom:4px">Slot '+(i+1)+'</div>';
    if(slot){
      html+='<div style="display:flex;align-items:center;justify-content:space-between">';
      html+='<span style="font-size:12px;font-weight:600">'+esc(slot.name||slot.memberId)+'</span>';
      html+='<button class="btn bred bsm" style="font-size:9px" data-idx="'+i+'" onclick="seedRemove(this.dataset.idx)">✕</button>';
      html+='</div>';
    } else {
      var taken=slots.map(function(s){return s?s.memberId:null;}).filter(Boolean);
      var avail=t.participants.filter(function(p){return taken.indexOf(p.memberId)<0;});
      html+='<select class="fs" style="font-size:11px" data-idx="'+i+'" onchange="seedAssign(this.dataset.idx,this.value)">';
      html+='<option value="">— Choisir —</option>';
      avail.forEach(function(p){html+='<option value="'+p.memberId+'">'+esc(p.name)+'</option>';});
      html+='</select>';
    }
    html+='</div>';
  });
  html+='</div>';
  OM('⚔️ Placement des équipes',html,[
    {lbl:'Annuler',cls:'bol',fn:CM},
    {lbl:'Démarrer',cls:'btn bg',fn:function(){
      var ordered=window._seedingSlots.slice();
      CM();
      launchTournament(window._seedingTournament,ordered);
    }}
  ]);
}

function seedAssign(idx,memberId){
  var t=window._seedingTournament;
  var p=(t.participants||[]).find(function(x){return x.memberId===memberId;});
  window._seedingSlots[parseInt(idx)]=p||null;
  showManualSeedingModal();
}

function seedRemove(idx){
  window._seedingSlots[parseInt(idx)]=null;
  showManualSeedingModal();
}

// Répare les votes orphelins : clés 'p...' dans vote_wars qui ne correspondent
// plus à aucun membre actuel (suite à l'ancien bug d'approbation qui changeait l'ID)
function repairOrphanVotes(){
  var memberIds={};
  DB.members.forEach(function(m){ memberIds[m.id]=true; });
  var orphans={}; // orphanId -> {count, wars, votes}
  (DB.voteWars||[]).forEach(function(w){
    Object.keys(w.votes||{}).forEach(function(vid){
      if(!memberIds[vid]){
        if(!orphans[vid]) orphans[vid]={count:0,wars:[],sample:w.votes[vid]};
        orphans[vid].count++;
        orphans[vid].wars.push(w.title);
      }
    });
  });
  var keys=Object.keys(orphans);
  if(!keys.length) return;
  // Si un seul membre non-admin existe, c'est probablement lui
  var nonAdminMembers=DB.members.filter(function(m){return m.role!=='admin'&&m.status!=='attente';});
  keys.forEach(function(oid){
    var info=orphans[oid];
    console.warn('[Votes orphelins] ID: '+oid+' | '+info.count+' vote(s) | Guerres: '+info.wars.join(', '));
    // Auto-fix si un seul membre non-admin et un seul orphelin
    if(keys.length===1&&nonAdminMembers.length===1){
      var target=nonAdminMembers[0];
      console.warn('[Auto-fix] Tentative: '+oid+' -> '+target.id+' ('+target.username+')');
      fixVoteKeys(oid, target.id);
    }
  });
}

