// IMAGE UPLOAD — Supabase Storage
// ════════════════════════════════════════════════════════════════
var SB_STORAGE_URL = SB_URL + '/storage/v1/object/public/media/';
var SB_STORAGE_UPLOAD = SB_URL + '/storage/v1/object/media/';


function resizeImage(file, maxW, maxH, quality){
  quality = quality || 0.85;
  return new Promise(function(resolve){
    var reader = new FileReader();
    reader.onload = function(e){
      var img = new Image();
      img.onload = function(){
        var w = img.width, h = img.height;
        // Calculate new dimensions keeping aspect ratio
        if(w > maxW){ h = Math.round(h * maxW / w); w = maxW; }
        if(h > maxH){ w = Math.round(w * maxH / h); h = maxH; }
        var canvas = document.createElement('canvas');
        canvas.width = w; canvas.height = h;
        var ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, w, h);
        canvas.toBlob(function(blob){
          // Create a new File from the blob
          var resized = new File([blob], file.name, {type: 'image/jpeg'});
          resolve(resized);
        }, 'image/jpeg', quality);
      };
      img.src = e.target.result;
    };
    reader.readAsDataURL(file);
  });
}


// ── Auto-resize images before upload ────────────────────────
function resizeImage(file, maxW, maxH, quality){
  return new Promise(function(resolve){
    var reader=new FileReader();
    reader.onload=function(e){
      var img=new Image();
      img.onload=function(){
        var w=img.width,h=img.height;
        var ratio=Math.min((maxW||1200)/w,(maxH||800)/h,1);
        var nw=Math.round(w*ratio),nh=Math.round(h*ratio);
        var canvas=document.createElement('canvas');
        canvas.width=nw;canvas.height=nh;
        canvas.getContext('2d').drawImage(img,0,0,nw,nh);
        canvas.toBlob(function(blob){
          resolve(blob?new File([blob],file.name,{type:'image/jpeg'}):file);
        },'image/jpeg',quality||0.85);
      };
      img.src=e.target.result;
    };
    reader.readAsDataURL(file);
  });
}

function uploadImage(file, onSuccess, onError) {
  // Max 5MB
  if(file.size > 5 * 1024 * 1024) {
    alert('Image trop grande (max 5MB)');
    if(onError) onError('too large');
    return;
  }
  var path = 'uploads/' + Date.now() + '_' + file.name.replace(/[^a-zA-Z0-9._-]/g, '_');
  var reader = new FileReader();
  reader.onload = function(e) {
    var base64 = e.target.result;
    // Try Supabase Storage first
    if(SB_READY) {
      var token = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inh3dHdtdGVxYm12d3FqeWljZ2FsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3ODAwNDM5MjksImV4cCI6MjA5NTYxOTkyOX0.wYU_YGFZIWXvEUwemRWycTK0vcrHRfSEpUzYL2ESE7E';
      fetch(SB_STORAGE_UPLOAD + path, {
        method: 'POST',
        headers: {
          'Authorization': 'Bearer ' + token,
          'Content-Type': file.type,
          'x-upsert': 'true'
        },
        body: file
      }).then(function(r) {
        if(r.ok) {
          var url = SB_STORAGE_URL + path;
          console.log('[IMG] Uploaded to Supabase:', url);
          if(onSuccess) onSuccess(url);
        } else {
          // Fallback to base64
          console.warn('[IMG] Supabase upload failed, using base64');
          if(onSuccess) onSuccess(base64);
        }
      }).catch(function() {
        if(onSuccess) onSuccess(base64);
      });
    } else {
      // Offline: use base64
      if(onSuccess) onSuccess(base64);
    }
  };
  reader.readAsDataURL(file);
}

// Reusable image picker widget HTML
function imgPickerHTML(inputId, currentUrl, placeholder) {
  placeholder = placeholder || 'Aucune image';
  return '<div style="margin-bottom:4px">'
    + (currentUrl ? '<img src="' + esc(currentUrl) + '" style="width:100%;height:180px;object-fit:cover;border-radius:3px;border:1px solid var(--b1);margin-bottom:8px;display:block">' : '')
    + '<input type="file" id="' + inputId + '" accept="image/*" style="display:none" onchange="previewImg(this)">'
    + '<label for="' + inputId + '" class="btn bol bsm" style="cursor:pointer;display:inline-block;margin-bottom:4px">📷 Choisir une image</label>'
    + (currentUrl ? ' <button class="btn bred bsm" data-iid="' + inputId + '" onclick="clearImg(this.dataset.iid)">✕ Retirer</button>' : '')
    + '<div id="' + inputId + '-preview" style="margin-top:8px"></div>'
    + '</div>';
}

function previewImg(input) {
  var preview = document.getElementById(input.id + '-preview');
  if(!preview || !input.files[0]) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    preview.innerHTML = '<img src="' + e.target.result + '" style="max-width:100%;max-height:160px;border-radius:3px;border:1px solid var(--golddim)">';
  };
  reader.readAsDataURL(input.files[0]);
}

function clearImg(inputId) {
  var inp = document.getElementById(inputId);
  if(inp) inp.value = '';
  // Clear file preview
  var prev = document.getElementById(inputId + '-preview');
  if(prev) prev.innerHTML = '';
  // Hide current image and add hidden flag to delete it
  var container = inp ? inp.closest('div') : null;
  if(container) {
    var currentImg = container.querySelector('img');
    if(currentImg) currentImg.style.display = 'none';
    var retirer = container.querySelector('button');
    if(retirer) retirer.style.display = 'none';
    // Mark as cleared
    var flag = document.getElementById(inputId+'-cleared');
    if(!flag) {
      flag = document.createElement('input');
      flag.type = 'hidden';
      flag.id = inputId+'-cleared';
      flag.value = '1';
      container.appendChild(flag);
    }
    // Show confirmation
    var msg = document.getElementById(inputId+'-cleared-msg');
    if(!msg) {
      msg = document.createElement('div');
      msg.id = inputId+'-cleared-msg';
      msg.style.cssText = 'font-size:11px;color:var(--red3);margin-top:4px';
      msg.textContent = '✕ Image retirée';
      container.appendChild(msg);
    }
  }
}

// Get image URL from file input (returns Promise)
function isImgCleared(inputId) {
  var flag = document.getElementById(inputId+'-cleared');
  return flag && flag.value === '1';
}

function getImgUrl(inputId, maxW, maxH) {
  // Auto-detect dimensions by context
  if(!maxW){
    if(inputId.indexOf('nbt')>=0||inputId.indexOf('bt-')>=0){maxW=1200;maxH=380;} // bannière panoramique
    else if(inputId.indexOf('nfo')>=0||inputId.indexOf('ef-')>=0){maxW=900;maxH=900;} // formation carré
    else if(inputId.indexOf('ne-')>=0||inputId.indexOf('ee-')>=0){maxW=1000;maxH=600;} // événement
    else{maxW=1000;maxH=800;} // forum, défaut
  }
  return new Promise(function(resolve) {
    if(typeof isImgCleared!=='undefined'&&isImgCleared(inputId)){ resolve(''); return; }
    var inp = document.getElementById(inputId);
    if(!inp || !inp.files || !inp.files[0]) { resolve(null); return; }
    resizeImage(inp.files[0], maxW, maxH).then(function(resized){
      uploadImage(resized, resolve, function(){ resolve(null); });
    });
  });
}

