  q=q.toLowerCase();var results=[];
  (DB.members||[]).forEach(function(m){if(m.username.toLowerCase().indexOf(q)>=0)results.push({type:'Membre',title:m.username,sub:RN[m.role]||m.role,action:function(){CM();go('mbr');}});});
  (DB.forumThreads||[]).filter(function(t){return typeof TAG_LBL!=='undefined'&&Object.keys(TAG_LBL).indexOf(t.tag)>=0;}).forEach(function(t){if(t.title.toLowerCase().indexOf(q)>=0)results.push({type:'Forum',title:t.title,sub:t.author,action:function(id){return function(){CM();go('for');};}(t.id)});});
  (DB.formations||[]).forEach(function(f){if(f.title.toLowerCase().indexOf(q)>=0)results.push({type:'Formation',title:f.title,sub:f.desc||'',action:function(id){return function(){CM();go('form');};}(f.id)});});
  (DB.voteWars||[]).forEach(function(w){if(w.title.toLowerCase().indexOf(q)>=0)results.push({type:'Guerre',title:w.title,sub:w.date,action:function(){CM();go('vote');}});});
  (DB.events||[]).forEach(function(e){if(e.title.toLowerCase().indexOf(q)>=0)results.push({type:'Événement',title:e.title,sub:e.date,action:function(){CM();go('cal');}});});
  if(!results.length){res.innerHTML='<div class="td tsm" style="padding:8px">Aucun résultat pour "'+esc(q)+'"</div>';return;}
  res.innerHTML=results.slice(0,20).map(function(r,i){return'<div onclick="gsActions['+i+']()" class="gs-item" style="padding:10px 14px;border-bottom:1px solid var(--b1);cursor:pointer;display:flex;align-items:center;gap:10px"><div style="font-size:10px;color:var(--tx3);min-width:80px">'+r.type+'</div><div><div style="font-size:13px;font-weight:600;color:var(--tx1)">'+esc(r.title)+'</div>'+(r.sub?'<div style="font-size:10px;color:var(--tx3)">'+esc(r.sub)+'</div>':'')+'</div></div>';}).join('');
