// PLANNING
// ════════════════════════════════════════

// ════════════════════════════════════════════════════════════════
// HIÉRARCHIE DE LA MAISON
// ════════════════════════════════════════════════════════════════
var HIER_TITRES = ['Baron','Bras droit','Intendant','Officier recruteur','Référent recruteur','Raid Lead','Recruteur','Formateur'];
var HIER_COLORS = {
  'Baron':              {border:'#c9a227',bg:'rgba(201,162,39,.15)',color:'#c9a227'},
  'Bras droit':         {border:'#ce93d8',bg:'rgba(206,147,216,.12)',color:'#ce93d8'},
  'Intendant':          {border:'#64b5f6',bg:'rgba(100,181,246,.12)',color:'#64b5f6'},
  'Officier recruteur': {border:'#ef5350',bg:'rgba(239,83,80,.1)',color:'#ef5350'},
  'Référent recruteur': {border:'#ef5350',bg:'rgba(239,83,80,.1)',color:'#ef5350'},
  'Raid Lead':          {border:'#66bb6a',bg:'rgba(102,187,106,.1)',color:'#66bb6a'},
  'Recruteur':          {border:'#ffa726',bg:'rgba(255,167,38,.1)',color:'#ffa726'},
  'Formateur':          {border:'#7090a8',bg:'rgba(112,144,168,.1)',color:'#7090a8'}
};

function sbSaveHierarchyNode(n){ return SB.from('hierarchy').upsert(n); }
function sbDeleteHierarchyNode(id){ return SB.from('hierarchy').delete('id',id); }

function pgHierarchy(){
  var canEdit=HR('baron')||HR('admin');
  if(canEdit) document.getElementById('tact').innerHTML='<button class="btn bg bsm" onclick="openAddHierNode()">+ Ajouter un poste</button>';
  else document.getElementById('tact').innerHTML='';

  var nodes=(DB.hierarchy||[]).slice().sort(function(a,b){return (a.ordre||0)-(b.ordre||0);});
  if(!nodes.length){
    return'<div class="pan"><div class="ph"><span class="ptl">⚜️ Hiérarchie de la Maison</span></div>'
      +'<div class="pb td ta-c" style="padding:40px;color:var(--tx3)">Aucun poste défini.</div></div>';
  }

  // Grouper par titre+ordre → membres du même titre et même ordre sont côte à côte
  var groups=[];
  nodes.forEach(function(n){
    var last=groups[groups.length-1];
    if(last&&last.titre===n.titre&&last.ordre===n.ordre){
      last.items.push(n);
    } else {
      groups.push({titre:n.titre,ordre:n.ordre,items:[n]});
    }
  });

  var html='<div class="pan"><div class="ph"><span class="ptl">⚜️ Hiérarchie de la Maison</span></div><div class="pb">';
  groups.forEach(function(grp){
    var col=HIER_COLORS[grp.titre]||{border:'var(--b2)',bg:'var(--bg1)',color:'var(--tx2)'};
    html+='<div style="margin-bottom:20px">';
    html+='<div style="font-family:Cinzel,serif;font-size:10px;font-weight:700;color:'+col.color
      +';letter-spacing:2px;text-transform:uppercase;margin-bottom:10px;border-bottom:1px solid '
      +col.border+';padding-bottom:6px">'+grp.titre+'</div>';
    html+='<div style="display:flex;flex-wrap:wrap;gap:10px">';
    grp.items.forEach(function(n){
      var m=DB.members.find(function(x){return x.id===n.membre_id;});
      html+='<div style="background:'+col.bg+';border:1px solid '+col.border
        +';border-radius:4px;padding:12px 16px;display:flex;align-items:center;gap:10px;min-width:160px">';
      if(m) html+=avaHTML(m,32);
      else html+='<div style="width:32px;height:32px;border-radius:50%;background:var(--bg2);display:flex;align-items:center;justify-content:center;font-size:14px;color:var(--tx3)">?</div>';
      html+='<div>';
      html+='<div style="font-size:13px;font-weight:700;color:var(--tx1);font-family:Cinzel,serif">'+esc(n.username||'—')+'</div>';
      if(m&&m.chefGroupe)    html+='<div style="font-size:10px;color:var(--teal2)">🗡️ Chef de Groupe</div>';
      if(m&&m.sanguin)       html+='<div style="font-size:10px;color:var(--tx3)">🩸 Garde Sanguin</div>';
      if(m&&m.grandChampion) html+='<div style="font-size:10px;color:var(--gold)">🏆 Grand Champion</div>';
      if(n.note)             html+='<div style="font-size:10px;color:var(--tx3);font-style:italic;margin-top:2px">'+esc(n.note)+'</div>';
      html+='</div>';
      if(canEdit){
        html+='<div style="margin-left:auto;display:flex;gap:4px">'
          +'<button class="btn bol bsm" style="font-size:10px" onclick="openEditHierNodeW(this)" data-id="'+n.id+'">✏️</button>'
          +'<button class="btn bred bsm" style="font-size:10px" onclick="delHierNodeW(this)" data-id="'+n.id+'">✕</button>'
          +'</div>';
      }
      html+='</div></div>';
    });
    html+='</div></div>';
  });
  html+='</div></div>';
  return html;
}

function memberDropdown(selectedId){
  var opts=DB.members.filter(function(m){return m.status!=='attente';})
    .sort(function(a,b){return a.username.localeCompare(b.username);})
    .map(function(m){return'<option value="'+esc(m.id)+'"'+(m.id===selectedId?' selected':'')+'>'+esc(m.username)+'</option>';}).join('');
  return'<select class="fs" id="hier-mb"><option value="">— Choisir un membre —</option>'+opts+'</select>';
}

function openAddHierNode(){
  if(!HR('baron')&&!HR('admin'))return;
  OM('Ajouter un poste',
    '<div class="fg"><label class="fl">Titre</label><select class="fs" id="hier-titre">'+HIER_TITRES.map(function(t){return'<option value="'+t+'">'+t+'</option>';}).join('')+'</select></div>'
    +'<div class="fg"><label class="fl">Membre</label>'+memberDropdown('')+'</div>'
    +'<div class="fg"><label class="fl">Note (optionnel)</label><textarea class="ft" id="hier-note" style="min-height:60px"></textarea></div>'
    +'<div class="fg"><label class="fl">Ordre</label><input class="fi" type="number" id="hier-ordre" value="0" style="max-width:80px"></div>',
    [{lbl:'Annuler',cls:'bol',fn:CM},{lbl:'Ajouter',cls:'btn bg',fn:function(){
      var titre=document.getElementById('hier-titre').value;
      var mbId=document.getElementById('hier-mb').value;
      var note=document.getElementById('hier-note').value.trim();
      var ordre=parseInt(document.getElementById('hier-ordre').value)||0;
      if(!mbId)return alert('Choisissez un membre.');
      var m=DB.members.find(function(x){return x.id===mbId;});
      var node={id:'h'+Date.now(),titre:titre,membre_id:mbId,username:m?m.username:'',note:note,ordre:ordre,updated_at:new Date().toISOString()};
      DB.hierarchy=DB.hierarchy||[];
      DB.hierarchy.push(node);
      sbSaveHierarchyNode(node).then(function(){CM();go('hier');}).catch(function(e){console.warn('[hier]',e);});
    }}]);
}

function openEditHierNodeW(btn){ openEditHierNode(btn.dataset.id); }
function openEditHierNode(id){
  if(!HR('baron')&&!HR('admin'))return;
  var n=(DB.hierarchy||[]).find(function(x){return x.id===id;});if(!n)return;
  OM('Modifier le poste',
    '<div class="fg"><label class="fl">Titre</label><select class="fs" id="hier-titre">'+HIER_TITRES.map(function(t){return'<option value="'+t+'"'+(t===n.titre?' selected':'')+'>'+t+'</option>';}).join('')+'</select></div>'
    +'<div class="fg"><label class="fl">Membre</label>'+memberDropdown(n.membre_id)+'</div>'
    +'<div class="fg"><label class="fl">Note (optionnel)</label><textarea class="ft" id="hier-note" style="min-height:60px">'+esc(n.note||'')+'</textarea></div>'
    +'<div class="fg"><label class="fl">Ordre</label><input class="fi" type="number" id="hier-ordre" value="'+(n.ordre||0)+'" style="max-width:80px"></div>',
    [{lbl:'Annuler',cls:'bol',fn:CM},{lbl:'Sauvegarder',cls:'btn bg',fn:function(){
      var mbId=document.getElementById('hier-mb').value;
      if(!mbId)return alert('Choisissez un membre.');
      var m=DB.members.find(function(x){return x.id===mbId;});
      n.titre=document.getElementById('hier-titre').value;
      n.membre_id=mbId; n.username=m?m.username:'';
      n.note=document.getElementById('hier-note').value.trim();
      n.ordre=parseInt(document.getElementById('hier-ordre').value)||0;
      n.updated_at=new Date().toISOString();
      sbSaveHierarchyNode(n).then(function(){CM();go('hier');}).catch(function(e){console.warn('[hier]',e);});
    }}]);
}

function delHierNodeW(btn){ delHierNode(btn.dataset.id); }
function delHierNode(id){
  if(!HR('baron')&&!HR('admin'))return;
  if(!confirm('Supprimer ce poste ?'))return;
  DB.hierarchy=(DB.hierarchy||[]).filter(function(x){return x.id!==id;});
  sbDeleteHierarchyNode(id).then(function(){go('hier');}).catch(function(e){console.warn('[hier]',e);});
}

function pgPlanning(){
  var now=new Date();
  var startOfWeek=new Date(now);
  var day=now.getDay();
  startOfWeek.setDate(now.getDate()-(day===0?6:day-1));
  var dayShort=['LUN','MAR','MER','JEU','VEN','SAM','DIM'];
  var weekDays=[];
  for(var i=0;i<7;i++){var d=new Date(startOfWeek);d.setDate(startOfWeek.getDate()+i);weekDays.push(d);}
  var h='<div class="pan"><div class="ph"><span class="ptl">📅 Semaine du '+weekDays[0].toLocaleDateString('fr-FR')+'</span></div><div class="pb" style="padding:0">';
  weekDays.forEach(function(d,i){
    var ds=d.toISOString().slice(0,10);
    var isToday=ds===now.toISOString().slice(0,10);
    var dayEvents=(DB.events||[]).filter(function(e){return e.date===ds;});
    var dayWars=(DB.voteWars||[]).filter(function(w){
      if(!w.date) return false;
      // Handle different date formats: YYYY-MM-DD or DD/MM/YYYY
      var wd=w.date;
      if(wd.indexOf('/')>=0){
        var parts=wd.split('/');
        if(parts.length===3) wd=parts[2]+'-'+(parts[1].length===1?'0':'')+parts[1]+'-'+(parts[0].length===1?'0':'')+parts[0];
      }
      return wd===ds;
    });
    h+='<div style="border-bottom:1px solid var(--b1);'+(isToday?'background:rgba(201,162,39,.05)':'')+'"><div style="display:flex;align-items:flex-start;padding:10px 16px;gap:12px"><div style="min-width:70px"><div style="font-size:10px;font-weight:700;color:'+(isToday?'var(--gold)':'var(--tx3)')+';letter-spacing:1px">'+dayShort[i]+'</div><div style="font-size:20px;font-weight:700;color:'+(isToday?'var(--gold)':'var(--tx1)')+'">'+d.getDate()+'</div>'+(isToday?'<div style="font-size:9px;color:var(--gold);font-weight:700">Auj.</div>':'')+'</div>';
    if(!dayEvents.length&&!dayWars.length){h+='<div style="color:var(--tx4);font-size:12px;font-style:italic;padding-top:6px">Aucun événement</div>';}
    else{h+='<div style="flex:1;display:flex;flex-direction:column;gap:6px">';
      dayWars.forEach(function(w){var mv=(w.votes||{})[CU.id];var vc=mv?(mv.vote==='present'?'#66bb6a':mv.vote==='absent'?'var(--red3)':'var(--tx3)'):'var(--tx3)';var vl=mv?(mv.vote==='present'?'✅ Présent':mv.vote==='absent'?'❌ Absent':''):'⏳ Sans vote';h+='<div style="background:rgba(139,26,10,.15);border:1px solid var(--red2);border-radius:3px;padding:8px 12px;display:flex;align-items:center;gap:10px"><span style="font-size:16px">⚔️</span><div style="flex:1"><div style="font-size:13px;font-weight:700;color:var(--tx1)">'+esc(w.title)+'</div>'+(w.time?'<div style="font-size:11px;color:var(--tx3)">'+esc(w.time)+'</div>':'')+'</div><span style="font-size:11px;font-weight:700;color:'+vc+'">'+vl+'</span></div>';});
      dayEvents.forEach(function(e){h+='<div style="background:rgba(201,162,39,.1);border:1px solid var(--golddim);border-radius:3px;padding:8px 12px;display:flex;align-items:center;gap:10px"><span style="font-size:16px">📅</span><div style="flex:1"><div style="font-size:13px;font-weight:700;color:var(--tx1)">'+esc(e.title)+'</div>'+(e.time?'<div style="font-size:11px;color:var(--tx3)">'+esc(e.time)+'</div>':'')+'</div></div>';});
      h+='</div>';}
    h+='</div></div>';
  });
  return h+'</div></div>';
}

// ════════════════════════════════════════
// THÈMES
// ════════════════════════════════════════
var THEMES={
  dark:{name:'Sang & Acier',desc:'Noir profond, rouge sang, argent',bg0:'#06060a',bg1:'#0c0b10',bg2:'#111018',bg3:'#18161f',b1:'rgba(200,180,220,.07)',b2:'rgba(200,180,220,.13)',tx1:'#e8e4f0',tx2:'#b0a8c0',tx3:'#6a6278',tx4:'#302840',gold:'#c9a227',golddim:'rgba(201,162,39,.28)',red2:'#8b0a12',red3:'#d42030',teal2:'#7090a8'},
  light:{name:'Parchemin de Guerre',desc:'Pierre grise, rouge bordeaux, argent',bg0:'#1a1820',bg1:'#201e28',bg2:'#262430',bg3:'#2c2a38',b1:'rgba(180,160,210,.1)',b2:'rgba(180,160,210,.18)',tx1:'#d8d0e8',tx2:'#a098b8',tx3:'#605870',tx4:'#302838',gold:'#c9a227',golddim:'rgba(201,162,39,.28)',red2:'#7a0810',red3:'#c01828',teal2:'#6080a0'}
};
function applyThemeEl(el){
  var key=el.dataset.theme;
  applyTheme(key);
  if(CU){CU.theme=key;sbSaveMember(CU).catch(function(e){console.warn('[theme]',e);});}
  // Re-render the theme picker to update selection highlight
  var picker=document.getElementById('theme-picker-wrap');
  if(picker) picker.innerHTML=themePickerHTML();
}
function applyTheme(key){
  var t=THEMES[key];if(!t)return;
  var r=document.documentElement.style;
  r.setProperty('--bg0',t.bg0);r.setProperty('--bg1',t.bg1);r.setProperty('--bg2',t.bg2);r.setProperty('--bg3',t.bg3);
  r.setProperty('--b1',t.b1);r.setProperty('--b2',t.b2||t.b1);
  r.setProperty('--tx1',t.tx1);r.setProperty('--tx2',t.tx2);r.setProperty('--tx3',t.tx3);r.setProperty('--tx4',t.tx4);
  r.setProperty('--gold',t.gold);r.setProperty('--golddim',t.golddim);
  r.setProperty('--red2',t.red2);r.setProperty('--red3',t.red3);r.setProperty('--teal2',t.teal2);
  try{localStorage.setItem('fs_theme',key);}catch(e){}
}
function loadTheme(){try{var k=localStorage.getItem('fs_theme');if(k&&THEMES[k])applyTheme(k);}catch(e){}}
function themePickerHTML(){
  var current='dark';try{current=localStorage.getItem('fs_theme')||'dark';}catch(e){}
  if(CU&&CU.theme)current=CU.theme;
  return'<div style="display:flex;gap:12px;flex-wrap:wrap">'+Object.entries(THEMES).map(function(entry){var key=entry[0],t=entry[1],active=current===key;return'<div onclick="applyThemeEl(this)" data-theme="'+key+'" style="cursor:pointer;border:2px solid '+(active?t.gold:t.b1)+';border-radius:4px;overflow:hidden;min-width:140px;opacity:'+(active?'1':'.75')+'"><div style="background:'+t.bg1+';padding:10px 12px;border-bottom:1px solid '+t.b1+'"><div style="display:flex;gap:4px;margin-bottom:6px"><div style="width:30px;height:6px;border-radius:2px;background:'+t.gold+'"></div><div style="width:50px;height:6px;border-radius:2px;background:'+t.tx3+'"></div></div><div style="display:flex;gap:4px"><div style="flex:1;height:30px;border-radius:2px;background:'+t.bg3+';border:1px solid '+t.b1+'"></div><div style="flex:1;height:30px;border-radius:2px;background:'+t.bg3+';border:1px solid '+t.b1+'"></div></div></div><div style="background:'+t.bg2+';padding:8px 12px"><div style="font-size:12px;font-weight:700;color:'+t.tx1+'">'+t.name+'</div><div style="font-size:10px;color:'+t.tx3+'">'+t.desc+'</div>'+(active?'<div style="font-size:9px;color:'+t.gold+';margin-top:4px;font-weight:700">✓ Actif</div>':'')+'</div></div>';}).join('')+'</div>';
}

// ════════════════════════════════════════
// EXPORT PDF
// ════════════════════════════════════════
function exportGroupsPDF(warId){
  var war=(DB.voteWars||[]).find(function(w){return w.id===warId;});
  var groups=(DB.groups||[]).filter(function(g){return g.warId===warId&&!g.archived;});
  if(!groups.length){alert('Aucun groupe pour cette guerre.');return;}
  var win=window.open('','_blank');
  if(!win){alert('Autorisez les pop-ups pour exporter.');return;}
  var html='<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Composition</title><style>body{font-family:serif;padding:20px;color:#111}h1{text-align:center;border-bottom:2px solid #8b1a1a;padding-bottom:8px}h2{color:#8b1a1a;margin-top:20px}.group{border:1px solid #ccc;border-radius:4px;margin-bottom:16px;padding:12px}.slots{display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin-top:10px}.slot{border:1px solid #ddd;border-radius:3px;padding:8px;text-align:center;font-size:11px}@media print{body{padding:0}}</style></head><body><h1>⚔️ '+(war?esc(war.title):'Groupes')+'</h1><p style="text-align:center;color:#666">'+(war?war.date:'')+'</p>'+groups.map(function(g){var lead=gM(g.leaderId);return'<div class="group"><h2>'+esc(g.name)+'</h2><p>Chef: <strong>'+(lead?esc(lead.username):'—')+'</strong></p><div class="slots">'+(g.members||[]).map(function(mid){var mb=gM(mid);var units=(g.unitAssignments&&g.unitAssignments[mid])||[];var cls=(g.classAssignments&&g.classAssignments[mid])||'';return'<div class="slot"><strong>'+(mb?esc(mb.username):'—')+'</strong>'+(cls?'<div style="color:#8b1a1a;font-size:10px">'+esc(cls)+'</div>':'')+units.filter(Boolean).map(function(u){return'<div style="font-size:10px">'+esc(u)+'</div>';}).join('')+'</div>';}).join('')+'</div></div>';}).join('')+'</body></html>';
  win.document.write(html);win.document.close();
  setTimeout(function(){win.print();},400);
}

