function openSanctions(memberId){
  if(!HR('officier'))return;
  var m=gM(memberId);if(!m)return;
  if(!m.sanctions)m.sanctions=[];
  var html='<div style="margin-bottom:12px"><div style="font-size:11px;color:var(--red3);font-weight:700;margin-bottom:8px">⚠️ Visible uniquement par les officiers+</div>'+(m.sanctions.length?m.sanctions.map(function(s,i){return'<div style="padding:8px 12px;background:rgba(139,26,10,.1);border:1px solid var(--red2);border-radius:3px;margin-bottom:6px;display:flex;justify-content:space-between;align-items:flex-start"><div><div style="font-size:12px;font-weight:700;color:var(--red3)">'+esc(s.type)+'</div><div style="font-size:11px;color:var(--tx2)">'+esc(s.note)+'</div><div style="font-size:10px;color:var(--tx4)">'+esc(s.by)+' · '+esc(s.date)+'</div></div><button class="btn bred bsm" onclick="removeSanctionEl(this)" data-mid="'+memberId+'" data-idx="'+i+'" style="font-size:9px">✕</button></div>';}).join(''):'<div class="td tsm" style="margin-bottom:8px">Aucun avertissement.</div>')+'</div><div class="fg"><label class="fl">Type</label><select class="fs" id="san-type"><option>⚠️ Avertissement</option><option>🔴 Avertissement grave</option><option>📝 Note</option><option>✅ Félicitations</option></select></div><div class="fg"><label class="fl">Note</label><textarea class="ft" id="san-note" style="min-height:60px" placeholder="Détails..."></textarea></div>';
  OM('⚠️ Sanctions — '+esc(m.username),html,[{lbl:'Annuler',cls:'bol',fn:CM},{lbl:'Ajouter',cls:'btn bred',fn:function(){var type=gVal('san-type'),note=gVal('san-note').trim();if(!note)return alert('Note requise');m.sanctions.push({type:type,note:note,by:CU.username,date:nowDate()});sbSaveMember(m).catch(function(e){console.warn(e);});CM();}}]);
}
function removeSanctionEl(el){removeSanction(el.dataset.mid,parseInt(el.dataset.idx));}
function removeSanction(memberId,idx){var m=gM(memberId);if(!m||!m.sanctions)return;m.sanctions.splice(idx,1);sbSaveMember(m).catch(function(e){console.warn(e);});CM();}

// ════════════════════════════════════════
// BADGES
// ════════════════════════════════════════
function getBadgeState(){try{return JSON.parse(sessionStorage.getItem('badge_state')||'{}');}catch(e){return{};}}
function setBadgeState(key,val){var s=getBadgeState();s[key]=val;try{sessionStorage.setItem('badge_state',JSON.stringify(s));}catch(e){}}
function markSeen(section){
  var now=new Date().getTime();
  if(section==='forum')setBadgeState('last_forum',now);
  if(section==='form')setBadgeState('last_form',now);
  if(section==='vote')setBadgeState('last_vote',now);
  if(section==='grp')setBadgeState('last_grp',now);
  if(section==='cal')setBadgeState('last_cal',now);
  if(section==='banner')setBadgeState('last_banner',now);
  updateAppBadge();
}
function updateAppBadge(){
  if(!CU)return;
  var count=0,state=getBadgeState(),badges={home:0,vote:0,grp:0,for:0,form:0,cal:0,rec:0};
  if(typeof canApproveRec==='function'&&canApproveRec()){badges.rec=(DB.pendingMembers||[]).filter(function(p){return p.status==='attente';}).length;count+=badges.rec;}
  var lastBanner=state['last_banner']||0;
  badges.home+=(DB.banners||[]).filter(function(b){return b.active&&b.createdAt&&new Date(b.createdAt).getTime()>lastBanner;}).length;
  (DB.voteWars||[]).filter(function(w){return w.status==='open';}).forEach(function(w){if(!(w.votes&&w.votes[CU.id]))badges.vote++;});
  count+=badges.vote;
  var lastForum=state['last_forum']||0;
  badges.for=(DB.forumThreads||[]).filter(function(t){return typeof TAG_LBL!=='undefined'&&Object.keys(TAG_LBL).indexOf(t.tag)>=0&&t.date&&new Date(t.date).getTime()>lastForum&&t.author!==CU.username;}).length;
  count+=badges.for;
  var lastForm=state['last_form']||0;
  badges.form=(DB.forumThreads||[]).filter(function(t){return typeof TAG_LBL_FORM!=='undefined'&&Object.keys(TAG_LBL_FORM).indexOf(t.tag)>=0&&t.date&&new Date(t.date).getTime()>lastForm&&t.author!==CU.username;}).length;
  badges.form+=(DB.formations||[]).filter(function(f){return f.createdAt&&new Date(f.createdAt).getTime()>lastForm&&f.createdBy!==CU.username;}).length;
  count+=badges.form;
  var lastCal=state['last_cal']||0;
  badges.cal=(DB.events||[]).filter(function(e){return e.createdAt&&new Date(e.createdAt).getTime()>lastCal;}).length;
  count+=badges.cal;
  if('setAppBadge' in navigator){if(count>0)navigator.setAppBadge(count).catch(function(){});else navigator.clearAppBadge().catch(function(){});}
  updateSidebarBadges(badges);
}
