function linkGroupToWar(gid){
  var g=gG(gid);if(!g)return;
  var wars=(DB.voteWars||[]).slice().sort(function(a,b){return b.date.localeCompare(a.date)});
  var warOpts='<option value="">— Aucune guerre —</option>'
    +wars.map(function(w){
      var ids=w.linkedGroupIds||(w.linkedGroupId?[w.linkedGroupId]:[]);
      var isLinked=ids.indexOf(gid)>=0;
      var status=w.status==='open'?'🟡 Vote ouvert':'✓ Clôturée';
      return'<option value="'+w.id+'"'+(isLinked?' selected':'')+'>'+esc(w.title)+' ('+w.date+') — '+status+'</option>';
    }).join('');
  OM('Lier une guerre à ce groupe',
    '<div class="fg"><label class="fl">Guerre de territoire</label><select class="fs" id="lgw-sel">'+warOpts+'</select></div>'
    +'<div style="font-size:11px;color:var(--tx3);margin-top:8px">💡 Les joueurs déjà dans un autre groupe de la même guerre ne peuvent pas être ajoutés ici.</div>',
    [{lbl:'Annuler',cls:'bol',fn:CM},{lbl:'⚠️ Sanctions',cls:'btn bred',fn:function(){CM();openSanctions(m.id);}},{lbl:'Sauvegarder',cls:'btn bg',fn:function(){
      var warId=gVal('lgw-sel');
      // Remove this group from all wars
      (DB.voteWars||[]).forEach(function(w){
        if(w.linkedGroupId===gid)w.linkedGroupId=null;
        if(w.linkedGroupIds)w.linkedGroupIds=w.linkedGroupIds.filter(function(id){return id!==gid});
      });
      // Link to selected war
      if(warId){
        var w=(DB.voteWars||[]).find(function(x){return x.id===warId});
        if(w){
          if(!w.linkedGroupIds)w.linkedGroupIds=w.linkedGroupId&&w.linkedGroupId!==gid?[w.linkedGroupId]:[];
          if(w.linkedGroupIds.indexOf(gid)<0)w.linkedGroupIds.push(gid);
          w.linkedGroupId=gid;
          sbSaveWar(w);
        }
      }
      sDB();CM();go('grp');
    }}]);
}

function archiveGrpW(el){
  var g=gG(el.dataset.id);if(!g)return;
  // If this group is linked to a war, offer to archive all war groups
  var linkedWar=(DB.voteWars||[]).find(function(w){var ids=w.linkedGroupIds||(w.linkedGroupId?[w.linkedGroupId]:[]);return ids.indexOf(g.id)>=0});
  if(linkedWar&&!g.archived){
    var warGroups=DB.groups.filter(function(x){return(DB.voteWars||[]).some(function(w){return w.linkedGroupId===x.id&&w.id===linkedWar.id})});
    if(warGroups.length>1&&confirm('Archiver tous les groupes liés à "'+linkedWar.title+'" ('+warGroups.length+' groupes) ?')){
      warGroups.forEach(function(x){x.archived=true;sbSaveGroup(x)});
      sDB();go('grp');return;
    }
  }
  g.archived=!g.archived;
  sbSaveGroup(g);go('grp');
}
