function ctaSelectorHTML(prefix, currentLabel, currentLink){
  var ctaLabels=['','Lire','Voter','Voir','Rejoindre','En savoir plus','Participer','Découvrir','Plus d\'infos'];
  // Build all items and store in global for search
  var allItems=[];
  [{val:'home',label:'🏠 Accueil'},{val:'mbr',label:'👥 Membres'},{val:'grp',label:'⚔️ Groupes de Combat'},
   {val:'vote',label:'🏴 Guerres — Vote'},{val:'for',label:'💬 Forum'},{val:'form',label:'📚 Formation'},
   {val:'cal',label:'📅 Calendrier'},{val:'rec',label:'📯 Recrutement'}
  ].forEach(function(x){allItems.push(x);});
  (DB.voteWars||[]).forEach(function(w){allItems.push({val:'vote:'+w.id,label:'⚔️ '+w.title+(w.status==='open'?' 🟢':' 🔴')});});
  (DB.formations||[]).forEach(function(f){allItems.push({val:'form:'+f.id,label:'📋 '+f.title});});
  (DB.forumThreads||[]).filter(function(t){return typeof TAG_LBL_FORM!=='undefined'&&Object.keys(TAG_LBL_FORM).indexOf(t.tag)>=0;}).forEach(function(t){allItems.push({val:'formthread:'+t.id,label:'📚 '+t.title});});
  (DB.forumThreads||[]).filter(function(t){return typeof TAG_LBL!=='undefined'&&Object.keys(TAG_LBL).indexOf(t.tag)>=0;}).forEach(function(t){allItems.push({val:'for:'+t.id,label:'💬 '+t.title});});
  (DB.events||[]).forEach(function(e){allItems.push({val:'cal:'+e.id,label:'📅 '+e.title});});
  // Store globally for search access
  window['_ctaItems_'+prefix]=allItems;
  var currentLabelDisplay=currentLink?(allItems.find(function(x){return x.val===currentLink;})||{label:''}).label:'';
  return '<div class="fg"><label class="fl">Texte du bouton CTA</label>'
    +'<select class="fs" id="'+prefix+'-lbl">'
    +ctaLabels.map(function(l){return'<option value="'+esc(l)+'"'+(currentLabel===l?' selected':'')+'>'+esc(l||'— Aucun bouton —')+'</option>';}).join('')
    +'</select></div>'
    +'<div class="fg"><label class="fl">Destination — tapez pour rechercher</label>'
    +'<div style="position:relative">'
    +'<input class="fi" id="'+prefix+'-search" placeholder="🔍 Section, guerre, sujet..." value="'+esc(currentLabelDisplay)+'" autocomplete="off"'
    +' data-prefix="'+prefix+'" oninput="ctaSearchEl(this)" onfocus="ctaSearchEl(this)">'
    +'<div id="'+prefix+'-results" style="display:none;position:absolute;top:100%;left:0;right:0;background:var(--bg2);border:1px solid var(--golddim);border-radius:3px;max-height:220px;overflow-y:auto;z-index:9999;box-shadow:0 4px 16px rgba(0,0,0,.5)"></div>'
    +'<input type="hidden" id="'+prefix+'-page" value="'+esc(currentLink||'')+'">'
    +'</div></div>';
}


function ctaSearchEl(input){
  var prefix=input.dataset.prefix;
  var items=window['_ctaItems_'+prefix]||[];
  var q=input.value.toLowerCase().trim();
  var filtered=q?items.filter(function(x){return x.label.toLowerCase().indexOf(q)>=0;}):items.slice(0,10);
  var res=document.getElementById(prefix+'-results');
  if(!res)return;
  if(!filtered.length){res.style.display='none';return;}
  res.innerHTML=filtered.map(function(x){
    return'<div style="padding:8px 12px;cursor:pointer;font-size:13px;border-bottom:1px solid var(--b1)" '
      +'onmousedown="ctaSelectEl(event,this)" data-prefix="'+prefix+'" data-val="'+esc(x.val)+'" data-label="'+esc(x.label)+'"'
      +' onmouseover="this.style.background=var(--bg3)" onmouseout="this.style.background=">'+esc(x.label)+'</div>';
  }).join('');
  res.style.display='block';
}

function ctaSelectEl(e, el){
  e.preventDefault();
  var prefix=el.dataset.prefix;
  document.getElementById(prefix+'-page').value=el.dataset.val;
  document.getElementById(prefix+'-search').value=el.dataset.label;
  document.getElementById(prefix+'-results').style.display='none';
}

